//
import { ORDINAL_DATATYPE } from '../../core/datatype-constants';
import { d3_scaleLinear, d3_scalePoint } from '../../core/d3-constants';
import { perToPx, pick, invokeFunction } from '../../utils/zcutils';
import { isHeatMapChartType } from '../../events/events-utils';

export function sizeRange(options = {}) {
    let tempScaleLinear = d3_scaleLinear(),
        tempScalePoint = d3_scalePoint();
    let { dim, bound, correction = _ => _ } = options;
    let chartObj = this.chartObj,
        config = this.getConfig(),
        userSizes = config.sizes,
        schema = this.schema.domain,
        domain = this.d3_scale.domain,
        dataType = this.schema.data.meta.datatype,
        ranges = schema.ranges,
        convertTo = _ => perToPx(_, dim);

    if (userSizes) {
        userSizes = invokeFunction(userSizes, chartObj, bound, this);
        return userSizes.map(convertTo);
    } else {
        let _default = correction(_defaultSize(config, chartObj, this, bound).map(convertTo), bound, this, chartObj);

        if (ranges || dataType === ORDINAL_DATATYPE) {
            let tempDomain = ranges || domain;
            tempScalePoint
                .domain(tempDomain) // multiple values
                .range(_default);

            return tempDomain.map(_ => tempScalePoint(_));
        } else {
            let tempDomain = [domain[0], domain[domain.length - 1]],
                mid = _default[0] + (_default[1] - _default[0]) / 2;

            tempScaleLinear
                .domain(tempDomain) // multiple stops may have
                .range(tempDomain[0] == tempDomain[1] ? [mid, mid] : _default);

            return domain.map(_ => tempScaleLinear(_));
        }
    }
}

function _defaultSize(config, chartObj, scaleComponent, bound) {
    let _default = _defaultPercent(chartObj, scaleComponent),
        minSize = invokeFunction(config.minSize, chartObj, bound, scaleComponent),
        maxSize = invokeFunction(config.maxSize, chartObj, bound, scaleComponent);

    return [pick(minSize, _default[0]), pick(maxSize, _default[1])];
}

function _defaultPercent(chartObj, scaleComponent) {
    if (_isMatrix(chartObj)) {
        return ['25%', '100%'];
    }

    if (chartObj.systemConf.legend.singleLayout && scaleComponent.encode === 'z') {
        return ['2.5%', '25%'];
    }

    return ['2%', '20%'];
}

function _isMatrix(chartObj) {
    let chartType = chartObj.chartTypes[0].value;
    return isHeatMapChartType(chartType);
}
